+      expect(toNormalizedUsage(acc)).toEqual({
+        input: 370,
+        output: 120,
+        cacheRead: 246_000,
+        cacheWrite: 5_000,
+        total: 251_490,
+      });
+    });
+
+    it("omits zero fields", () => {
+      const acc = createUsageAccumulator();
+      mergeUsageIntoAccumulator(acc, { input: 100, output: 50 });
+
+      expect(toNormalizedUsage(acc)).toEqual({
+        input: 100,
+        output: 50,
+        cacheRead: undefined,
+        cacheWrite: undefined,
+        total: 150,
+      });
