+          {
+            inputTokens: 99,
+            outputTokens: 12,
+            cache_read_input_tokens: 456,
+            cache_creation_input_tokens: 3,
+            totalTokens: 570,
+          },
+          acc,
+        ),
+      ).toEqual({
+        input: 99,
+        output: 12,
+        cacheRead: 456,
+        cacheWrite: 3,
+        total: 570,
+      });
+    });
+
+    it("falls back to the accumulator when assistant usage is missing", () => {
+      const acc = createUsageAccumulator();
+      mergeUsageIntoAccumulator(acc, {
+        input: 150,
+        output: 40,
+        cacheRead: 84_000,
+        cacheWrite: 0,
+        total: 84_190,
+      });
+
+      expect(resolveLastCallUsage(undefined, acc)).toEqual({
+        input: 150,
+        output: 40,
+        cacheRead: 84_000,
+        cacheWrite: undefined,
+        total: 84_190,
+      });
+    });
+
+    it("falls back when assistant usage exists but is unusable", () => {
+      const acc = createUsageAccumulator();
+      mergeUsageIntoAccumulator(acc, {
+        input: 150,
+        output: 40,
+        cacheRead: 84_000,
+        cacheWrite: 0,
+        total: 84_190,
+      });
+
+      expect(resolveLastCallUsage({ responseId: "abc" } as never, acc)).toEqual({
+        input: 150,
+        output: 40,
+        cacheRead: 84_000,
+        cacheWrite: undefined,
+        total: 84_190,
+      });
+    });
+
+    it("keeps an explicit zero-usage raw snapshot instead of falling back", () => {
+      const acc = createUsageAccumulator();
+      mergeUsageIntoAccumulator(acc, {
+        input: 150,
+        output: 40,
+        cacheRead: 84_000,
+        cacheWrite: 0,
+        total: 84_190,
+      });
+
+      expect(
+        resolveLastCallUsage(
+          {
+            input: 0,
+            output: 0,
+            cacheRead: 0,
+            cacheWrite: 0,
+            total: 0,
+          },
+          acc,
+        ),
+      ).toEqual({
+        input: 0,
+        output: 0,
+        cacheRead: 0,
+        cacheWrite: 0,
+        total: 0,
+      });
+    });
+  });
